(function($){'use strict';$(document).ready(function(){if(typeof woocommerce_admin_meta_boxes!=='undefined'){initializeTagsSelect()}else{setTimeout(initializeTagsSelect,500)}});function initializeTagsSelect(){const $select=$('#ghl_purchase_tags');if(!$select.length){return}
const savedTags=$select.data('saved-tags')||[];var allTags=(typeof ghl_crm_pro_woocommerce_data!=='undefined'&&ghl_crm_pro_woocommerce_data.tags)?ghl_crm_pro_woocommerce_data.tags:[];allTags.forEach(function(tag){var label=String(tag.name||tag.id||'');if(label&&!$select[0].querySelector('option[value="'+CSS.escape(label)+'"]')){var isSelected=savedTags.indexOf(label)!==-1;$select.append(new Option(label,label,isSelected,isSelected))}});$select.select2({placeholder:$select.data('placeholder')||'Select tags...',allowClear:!0,closeOnSelect:!1,tags:!0,tokenSeparators:[','],scrollAfterSelect:!1,width:'100%'});$select.on('select2:select select2:unselect',function(e){var $dropdown=$(this).data('select2').$dropdown;if($dropdown){var $results=$dropdown.find('.select2-results__options');if($results.length){var scrollPos=$results.scrollTop();setTimeout(function(){$results.scrollTop(scrollPos)},1)}}});if(savedTags.length>0){loadSavedTags($select,savedTags)}}
function loadSavedTags($select,tags){tags.forEach(function(tag){const option=new Option(tag,tag,!0,!0);$select.append(option)});$select.trigger('change')}})(jQuery)